class Solution:
    def removeComments(self, source: List[str]) -> List[str]:
        res, buf, block = [], [], False
        for line in source:
            i, n = 0, len(line)
            while i < n:
                if block:
                    j = line.find("*/", i)
                    if j == -1: i = n; break
                    i = j + 2; block = False
                elif i + 1 < n and line[i:i+2] == "//": break
                elif i + 1 < n and line[i:i+2] == "/*": block = True; i += 2
                else: buf.append(line[i]); i += 1
            if not block:
                res.append("".join(buf)); buf = []
        return res

